fragment TrackFields on ManifestState {
  id
  owner
  schemaId
  schemaName
  manifestCid
  version
  lastUpdated
}

query GetTracks($first: Int!, $skip: Int!) {
  manifestStates(
    first: $first
    skip: $skip
    orderBy: lastUpdated
    orderDirection: desc
    where: {schemaId: "0xf18e92dce6496a423a48614fac9fe93c549aa51c1a663f5cbe2233b0ea18081d"}
  ) {
    ...TrackFields
    manifest {
      files {
        name
        fileFields {
          name
          value
          atType
          acc
          pricing {
            price
            currency
          }
        }
      }
    }
  }
}

query SearchTracks($search: String!) {
  manifestStates(
    where: {schemaId: "0xf18e92dce6496a423a48614fac9fe93c549aa51c1a663f5cbe2233b0ea18081d"}
    first: 100
  ) {
    ...TrackFields
    manifest {
      files {
        name
        fileFields {
          name
          value
          atType
          acc
          pricing {
            price
            currency
          }
        }
      }
    }
  }
}

query GetTracksByOwner($owner: Bytes!, $first: Int!, $skip: Int!) {
  manifestStates(
    where: {owner: $owner, schemaId: "0xf18e92dce6496a423a48614fac9fe93c549aa51c1a663f5cbe2233b0ea18081d"}
    first: $first
    skip: $skip
  ) {
    ...TrackFields
    manifest {
      files {
        name
        fileFields {
          name
          value
          atType
          acc
          pricing {
            price
            currency
          }
        }
      }
    }
  }
}

query GetTrack($id: ID!) {
  manifestState(id: $id) {
    ...TrackFields
    manifest {
      files {
        name
        fileFields {
          name
          value
          atType
          acc
          pricing {
            price
            currency
          }
        }
      }
    }
  }
}

query GetTrackByOwnerAndTitle($owner: Bytes!, $title: String!) {
  manifestStates(
    where: {owner: $owner, schemaId: "0xf18e92dce6496a423a48614fac9fe93c549aa51c1a663f5cbe2233b0ea18081d"}
    first: 10
  ) {
    ...TrackFields
    manifest {
      files {
        name
        fileFields {
          name
          value
        }
      }
    }
  }
}
